(function() {
          'use strict';
          var QS_PLACEHOLDER = 'jc_xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx';
          // 3 prefix 互換: 新規は jc_、既発行の sk_ / am_ も valid のまま許容
          var KEY_RE = /^(jc_|sk_|am_)[A-Za-z0-9_-]{16,}$/;

          var tabs = document.querySelectorAll('.qs-tab');
          tabs.forEach(function (tab) {
            tab.addEventListener('click', function() {
              var target = tab.getAttribute('data-qs-target');
              tabs.forEach(function (t) {
                var active = t === tab;
                t.classList.toggle('qs-tab-active', active);
                t.setAttribute('aria-selected', active ? 'true' : 'false');
              });
              ['curl','claude','cursor','cline','chatgpt'].forEach(function (name) {
                var panel = document.getElementById('qs-panel-' + name);
                if (!panel) return;
                if (name === target) panel.removeAttribute('hidden');
                else panel.setAttribute('hidden', '');
              });
            });
          });

          function readKey() {
            try {
              var stored = localStorage.getItem('am_api_key');
              if (stored && KEY_RE.test(stored)) return stored;
            } catch (_e) {}
            var newkey = document.getElementById('dash-newkey-value');
            if (newkey && newkey.textContent && KEY_RE.test(newkey.textContent.trim())) {
              return newkey.textContent.trim();
            }
            return null;
          }
          function applyKey() {
            var key = readKey();
            var slots = document.querySelectorAll('.qs-key-slot');
            slots.forEach(function (s) {
              s.textContent = key || QS_PLACEHOLDER;
            });
          }
          applyKey();
          window.addEventListener('storage', applyKey);
          setTimeout(applyKey, 800);
          setTimeout(applyKey, 2200);

          document.querySelectorAll('.qs-copy').forEach(function (btn) {
            btn.addEventListener('click', function() {
              var src = document.getElementById(btn.getAttribute('data-copy-target'));
              if (!src) return;
              var text = src.textContent;
              var prev = btn.textContent;
              var done = function (ok) {
                btn.textContent = ok ? 'Copied' : 'Copy failed';
                setTimeout(function() { btn.textContent = prev || 'Copy'; }, 1800);
              };
              if (navigator.clipboard && navigator.clipboard.writeText) {
                navigator.clipboard.writeText(text).then(function() { done(true); }, function() { done(false); });
              } else {
                try {
                  var ta = document.createElement('textarea');
                  ta.value = text;
                  ta.setAttribute('readonly', '');
                  ta.style.position = 'absolute';
                  ta.style.left = '-9999px';
                  document.body.appendChild(ta);
                  ta.select();
                  document.execCommand('copy');
                  document.body.removeChild(ta);
                  done(true);
                } catch (_e) { done(false); }
              }
            });
          });
        })();

