(function() {
          'use strict';
          var API_BASE = (function() {
            try {
              var origin = window.location.origin || '';
              if (origin.indexOf('jpcite.com') !== -1) {
                return 'https://api.jpcite.com';
              }
              return origin;
            } catch (_e) { return ''; }
          })();
          var SECTION = document.getElementById('saved-searches');
          var TBODY = document.getElementById('saved-searches-tbody');
          var EMPTY = document.getElementById('saved-searches-empty');
          var BANNER = document.getElementById('saved-searches-banner');
          var FORM = document.getElementById('saved-searches-form');

          function readCookie(name) {
            var raw = document.cookie || '';
            var parts = raw.split(';');
            for (var i = 0; i < parts.length; i++) {
              var s = parts[i].trim();
              if (!s) continue;
              var eq = s.indexOf('=');
              var k = eq < 0 ? s : s.slice(0, eq);
              if (k === name) return eq < 0 ? '' : decodeURIComponent(s.slice(eq + 1));
            }
            return '';
          }
          function csrfHeaders() {
            var t = readCookie('am_csrf');
            return t ? { 'X-CSRF-Token': t } : {};
          }
          function api(path) { return API_BASE + path; }
          function setBanner(msg, isError) {
            if (!BANNER) return;
            BANNER.textContent = msg || '';
            BANNER.style.display = msg ? 'block' : 'none';
            BANNER.style.color = isError ? 'var(--danger)' : 'var(--text)';
            BANNER.style.background = isError ? '#fff5f5' : '#f4faf5';
          }
          async function fetchJSON(path, opts) {
            opts = opts || {};
            var init = {
              method: opts.method || 'GET',
              credentials: 'include',
              headers: Object.assign(
                { 'Accept': 'application/json' },
                opts.body ? { 'Content-Type': 'application/json' } : {},
                opts.headers || {}
              ),
            };
            if (opts.body) init.body = JSON.stringify(opts.body);
            var resp = await fetch(api(path), init);
            var text = await resp.text();
            var body = null;
            try { body = text ? JSON.parse(text) : null; } catch (_e) { body = null; }
            if (!resp.ok) {
              var detail = (body && (body.detail || body.message)) || ('HTTP ' + resp.status);
              if (typeof detail === 'object' && detail) {
                detail = detail.message || JSON.stringify(detail);
              }
              var err = new Error(detail);
              err.status = resp.status;
              throw err;
            }
            return body;
          }
          function escape(s) {
            if (s === null || typeof s === 'undefined') return '';
            return String(s)
              .replace(/&/g, '&amp;')
              .replace(/</g, '&lt;')
              .replace(/>/g, '&gt;')
              .replace(/"/g, '&quot;');
          }
          function fmtTs(s) {
            if (!s) return '—';
            return escape(String(s).slice(0, 16).replace('T', ' '));
          }
          function summariseQuery(q) {
            if (!q || typeof q !== 'object') return '';
            var bits = [];
            if (q.q) bits.push('q=' + q.q);
            if (q.prefecture) bits.push('地域=' + q.prefecture);
            if (Array.isArray(q.target_types) && q.target_types.length) {
              bits.push('対象=' + q.target_types.join('/'));
            }
            if (q.amount_max) bits.push('上限=' + q.amount_max);
            return bits.join(' · ');
          }
          function renderRows(rows) {
            if (!TBODY) return;
            TBODY.innerHTML = '';
            if (!rows || !rows.length) {
              if (EMPTY) EMPTY.style.display = 'block';
              return;
            }
            if (EMPTY) EMPTY.style.display = 'none';
            for (var i = 0; i < rows.length; i++) {
              var r = rows[i];
              var tr = document.createElement('tr');
              tr.style.borderBottom = '1px solid var(--border)';
              tr.innerHTML = ''
                + '<td style="padding:6px 4px;font-family:ui-monospace,SFMono-Regular,Menlo,monospace;">'
                + escape(r.id) + '</td>'
                + '<td style="padding:6px 4px;"><strong>' + escape(r.name) + '</strong>'
                + '<br><span style="color:var(--text-muted);font-size:12px;">'
                + escape(summariseQuery(r.query)) + '</span></td>'
                + '<td style="padding:6px 4px;">' + escape(r.frequency) + '</td>'
                + '<td style="padding:6px 4px;">' + escape(r.notify_email) + '</td>'
                + '<td style="padding:6px 4px;">' + fmtTs(r.last_run_at) + '</td>'
                + '<td style="padding:6px 4px;text-align:right;">'
                + '<button type="button" class="btn btn-secondary" data-saved-id="' + escape(r.id)
                + '" style="padding:5px 10px;font-size:12px;">削除</button></td>';
              TBODY.appendChild(tr);
            }
          }
          async function load() {
            try {
              var rows = await fetchJSON('/v1/me/saved_searches');
              renderRows(rows || []);
              setBanner('', false);
              if (SECTION) {
                SECTION.style.display = '';
                SECTION.removeAttribute('hidden');
              }
            } catch (err) {
              if (err && err.status === 401) {
                if (SECTION) SECTION.style.display = 'none';
                return;
              }
              setBanner('保存条件の取得に失敗しました: ' + (err && err.message ? err.message : ''), true);
            }
          }
          async function onSubmit(e) {
            e.preventDefault();
            var hp = document.getElementById('saved-searches-company-url');
            if (hp && hp.value) return;
            var name = (document.getElementById('saved-searches-name').value || '').trim();
            var q = (document.getElementById('saved-searches-q').value || '').trim();
            var prefecture = (document.getElementById('saved-searches-prefecture').value || '').trim();
            var rawTargets = (document.getElementById('saved-searches-target-types').value || '').trim();
            var amountMax = document.getElementById('saved-searches-amount-max').value;
            var frequency = document.getElementById('saved-searches-frequency').value;
            var email = (document.getElementById('saved-searches-email').value || '').trim();

            var query = {};
            if (q) query.q = q;
            if (prefecture) query.prefecture = prefecture;
            if (rawTargets) {
              query.target_types = rawTargets.split(',').map(function (s) { return s.trim(); }).filter(Boolean);
            }
            if (amountMax) query.amount_max = Number(amountMax);

            if (!name || !email || (!q && !prefecture && (!query.target_types || !query.target_types.length) && !query.amount_max)) {
              setBanner('名前・配信先 email・最低 1 つの条件 (q / 都道府県 / 対象事業者 / amount_max) は必須です。', true);
              return;
            }

            try {
              await fetchJSON('/v1/me/saved_searches', {
                method: 'POST',
                headers: csrfHeaders(),
                body: { name: name, query: query, frequency: frequency, notify_email: email },
              });
              setBanner('保存条件を登録しました。', false);
              FORM.reset();
              await load();
            } catch (err) {
              setBanner('登録に失敗しました: ' + (err && err.message ? err.message : ''), true);
            }
          }
          async function onDelete(e) {
            var btn = e.target;
            if (!btn || !btn.getAttribute) return;
            var id = btn.getAttribute('data-saved-id');
            if (!id) return;
            if (!confirm('保存条件 id=' + id + ' を削除します。よろしいですか?')) return;
            try {
              await fetchJSON('/v1/me/saved_searches/' + encodeURIComponent(id), {
                method: 'DELETE',
                headers: csrfHeaders(),
              });
              setBanner('削除しました (id=' + id + ')。', false);
              await load();
            } catch (err) {
              setBanner('削除に失敗しました: ' + (err && err.message ? err.message : ''), true);
            }
          }
          if (FORM) FORM.addEventListener('submit', onSubmit);
          if (TBODY) TBODY.addEventListener('click', onDelete);
          if (document.readyState === 'complete' || document.readyState === 'interactive') {
            setTimeout(load, 0);
          } else {
            document.addEventListener('DOMContentLoaded', load);
          }
        })();

